```java
package com.example.productapi.exception;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.time.LocalDateTime;
import java.util.LinkedHashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(BadRequestException.class)
    public ResponseEntity<Map<String, Object>> handleBadRequest(BadRequestException ex) {
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("timestamp", LocalDateTime.now());
        body.put("status", HttpStatus.BAD_REQUEST.value());
        body.put("error", "Bad Request");
        body.put("message", ex.getMessage());

        return ResponseEntity.badRequest().body(body);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> handleGeneric(Exception ex) {
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("timestamp", LocalDateTime.now());
        body.put("status", HttpStatus.INTERNAL_SERVER_ERROR.value());
        body.put("error", "Internal Server Error");
        body.put("message", ex.getMessage());

        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
    }
}
```

### service/ProductService.java

```java
package com.example.productapi.service;

import com.example.productapi.dto.ProductResponse;
import com.example.productapi.exception.BadRequestException;
import com.example.productapi.model.Product;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;
import java.util.stream.Collectors;
import java.util.stream.Stream;

@Service
public class ProductService {

    private final List<Product> products = new ArrayList<>();

    public ProductService() {
        products.add(new Product(1L, "iPhone 15", "Electronics", new BigDecimal("1200"), 4.8, true));
        products.add(new Product(2L, "Samsung TV", "Electronics", new BigDecimal("800"), 4.5, true));
        products.add(new Product(3L, "Office Chair", "Furniture", new BigDecimal("150"), 4.2, false));
        products.add(new Product(4L, "Gaming Laptop", "Electronics", new BigDecimal("1600"), 4.9, true));
        products.add(new Product(5L, "Wooden Table", "Furniture", new BigDecimal("300"), 4.1, true));
        products.add(new Product(6L, "Headphones", "Electronics", new BigDecimal("100"), 4.3, true));
    }

    public List<ProductResponse> getProducts(
            String category,
            BigDecimal minPrice,
            BigDecimal maxPrice,
            Boolean inStock,
            String sortBy,
            String direction
    ) {
        validatePriceRange(minPrice, maxPrice);
        validateSortInputs(sortBy, direction);

        Stream<Product> stream = products.stream();

        if (category != null && !category.isBlank()) {
            stream = stream.filter(product ->
                    product.getCategory() != null &&
                    product.getCategory().equalsIgnoreCase(category));
        }

        if (minPrice != null) {
            stream = stream.filter(product -> product.getPrice().compareTo(minPrice) >= 0);
        }

        if (maxPrice != null) {
            stream = stream.filter(product -> product.getPrice().compareTo(maxPrice) <= 0);
        }

        if (inStock != null) {
            stream = stream.filter(product -> product.isInStock() == inStock);
        }

        List<Product> filteredProducts = stream.collect(Collectors.toList());

        if (sortBy != null && !sortBy.isBlank()) {
            Comparator<Product> comparator = buildComparator(sortBy);

            if ("desc".equalsIgnoreCase(direction)) {
                comparator = comparator.reversed();
            }

            filteredProducts = filteredProducts.stream()
                    .sorted(comparator)
                    .collect(Collectors.toList());
        }

        return filteredProducts.stream()
                .map(this::toResponse)
                .collect(Collectors.toList());
    }

    private void validatePriceRange(BigDecimal minPrice, BigDecimal maxPrice) {
        if (minPrice != null && maxPrice != null && minPrice.compareTo(maxPrice) > 0) {
            throw new BadRequestException("minPrice cannot be greater than maxPrice.");
        }
    }

    private void validateSortInputs(String sortBy, String direction) {
        if (sortBy != null && !sortBy.isBlank()) {
            List<String> allowedSortFields = List.of("price", "rating", "name");
            if (!allowedSortFields.contains(sortBy.toLowerCase(Locale.ROOT))) {
                throw new BadRequestException("Invalid sortBy value. Allowed values: price, rating, name.");
            }
        }

        if (direction != null && !direction.isBlank()) {
            List<String> allowedDirections = List.of("asc", "desc");
            if (!allowedDirections.contains(direction.toLowerCase(Locale.ROOT))) {
                throw new BadRequestException("Invalid direction value. Allowed values: asc, desc.");
            }
        }
    }

    private Comparator<Product> buildComparator(String sortBy) {
        return switch (sortBy.toLowerCase(Locale.ROOT)) {
            case "price" -> Comparator.comparing(Product::getPrice);
            case "rating" -> Comparator.comparing(Product::getRating);
            case "name" -> Comparator.comparing(Product::getName, String.CASE_INSENSITIVE_ORDER);
            default -> throw new BadRequestException("Unsupported sortBy value.");
        };
    }

    private ProductResponse toResponse(Product product) {
        return new ProductResponse(
                product.getId(),
                product.getName(),
                product.getCategory(),
                product.getPrice(),
                product.getRating(),
                product.isInStock()
        );
    }
}
```

### controller/ProductController.java

```java
package com.example.productapi.controller;

import com.example.productapi.dto.ProductResponse;
import com.example.productapi.service.ProductService;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.math.BigDecimal;
import java.util.List;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @GetMapping
    public List<ProductResponse> getProducts(
            @RequestParam(required = false) String category,
            @RequestParam(required = false) BigDecimal minPrice,
            @RequestParam(required = false) BigDecimal maxPrice,
            @RequestParam(required = false) Boolean inStock,
            @RequestParam(required = false) String sortBy,
            @RequestParam(required = false, defaultValue = "asc") String direction
    ) {
        return productService.getProducts(category, minPrice, maxPrice, inStock, sortBy, direction);
    }
}
```

